"use client";

import { useState, useEffect } from "react";
import { cn } from "@/lib/utils";
import { useYtcnPlayer } from "./use-ytcn-player";
import { useKeyboardShortcuts } from "./use-keyboard-shortcuts";
import { useThumbnail } from "./use-thumbnail";
import type {
  YtcnPlayerOptions,
  KeyboardBindings,
} from "./types";
import { YtcnControls } from "./ytcn-controls";
import { useIdleControls } from "./use-idle-controls";
import { IconPlayerPlayFilled, IconLoader2 } from "@tabler/icons-react";

export interface YtcnPlayerProps extends Omit<YtcnPlayerOptions, "thumbnailFailed"> {
  keyboardShortcuts?: boolean;
  keyboardBindings?: KeyboardBindings;
  className?: string;
}

export function YtcnPlayer({
  videoId,
  autoplay = false,
  defaultSpeed = 1,
  startAt = 0,
  onEnd,
  onTimeUpdate,
  onPlaybackRateChange,
  keyboardShortcuts = true,
  keyboardBindings,
  className,
}: YtcnPlayerProps): React.JSX.Element {
  const { thumbnailUrl, thumbnailLoaded, thumbnailFailed } = useThumbnail(videoId);

  const { containerRef, playerDivRef, state, controls } = useYtcnPlayer({
    videoId,
    autoplay,
    defaultSpeed,
    startAt,
    onEnd,
    onTimeUpdate,
    onPlaybackRateChange,
    thumbnailFailed,
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const { controlsVisible, showControls } = useIdleControls({
    isPlaying: state.isPlaying,
    isFullscreen: state.isFullscreen,
    isSettingsOpen,
  });

  const [isHovering, setIsHovering] = useState(false);

  useKeyboardShortcuts({
    enabled: keyboardShortcuts && state.phase === "ready",
    onPlay: controls.togglePlay,
    onMute: controls.toggleMute,
    onFullscreen: controls.toggleFullscreen,
    onSeekBack: () => controls.seekRelative(-10),
    onSeekForward: () => controls.seekRelative(10),
    bindings: keyboardBindings,
  });

  const [thumbnailMounted, setThumbnailMounted] = useState(true);

  useEffect(() => {
    if (state.phase === "ready") {
      const t = setTimeout(() => setThumbnailMounted(false), 600);
      return () => clearTimeout(t);
    } else {
      setThumbnailMounted(true);
    }
  }, [state.phase]);

  return (
    <div
      ref={containerRef}
      role="region"
      aria-label="Video player"
      className={cn(
        "relative w-full bg-black select-none overflow-hidden",
        state.isFullscreen && !controlsVisible && "cursor-none",
        state.isFullscreen
          ? "fixed inset-0 z-50"
          : "aspect-video rounded-lg group",
        className
      )}
      onMouseEnter={() => { setIsHovering(true); showControls(); }}
      onMouseLeave={() => setIsHovering(false)}
      onMouseMove={() => { if (!isHovering) setIsHovering(true); showControls(); }}
    >
      {state.phase !== "thumbnail" && (
        <div className="absolute inset-0 z-0 overflow-hidden">
          <div ref={playerDivRef} className="w-full h-full" />
        </div>
      )}

      {state.phase === "loading" && (
        <div className="absolute inset-0 z-10 bg-black" aria-hidden="true" />
      )}

      {thumbnailMounted && thumbnailUrl && (
        <div
          className={cn(
            "absolute inset-0 z-20 transition-opacity duration-500",
            state.phase === "ready" ? "opacity-0 pointer-events-none" : "opacity-100"
          )}
        >
          <img
            src={thumbnailUrl}
            alt=""
            className="w-full h-full object-cover"
            draggable={false}
            aria-hidden="true"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent" />
        </div>
      )}

      {state.phase === "thumbnail" && !thumbnailLoaded && !thumbnailFailed && (
        <div className="absolute inset-0 z-20 bg-muted animate-pulse" />
      )}

      {state.phase === "loading" && (
        <div
          className="absolute inset-0 z-40 flex items-center justify-center pointer-events-none"
          aria-label="Loading video"
        >
          <IconLoader2 className="h-10 w-10 animate-spin text-white/80" />
        </div>
      )}

      {state.phase === "thumbnail" && thumbnailLoaded && (
        <button
          onClick={controls.handleThumbnailClick}
          className="absolute inset-0 z-40 flex items-center justify-center group/play bg-transparent border-0 cursor-pointer"
          aria-label="Play video"
        >
          <div
            className={cn(
              "flex items-center justify-center",
              "h-16 w-16 rounded-full",
              "bg-black/60 text-white",
              "transition-transform duration-200",
              "group-hover/play:scale-110"
            )}
          >
            <IconPlayerPlayFilled className="h-8 w-8 translate-x-0.5" fill="currentColor" />
          </div>
        </button>
      )}

      {state.phase === "ready" && (
        <>
          <div
            className="absolute inset-0 z-[25] cursor-pointer"
            onClick={controls.togglePlay}
            aria-label="Toggle playback"
            role="button"
            tabIndex={-1}
          />
          <YtcnControls
            state={state}
            onTogglePlay={controls.togglePlay}
            onSeek={controls.seekTo}
            onVolumeChange={controls.setVolume}
            onToggleMute={controls.toggleMute}
            onSpeedChange={controls.setSpeed}
            onToggleFullscreen={controls.toggleFullscreen}
            visible={controlsVisible}
            containerRef={containerRef}
            onSettingsOpenChange={setIsSettingsOpen}
            onInteraction={showControls}
          />
        </>
      )}
    </div>
  );
}

"use client";

import {
  IconPlayerPlayFilled,
  IconPlayerPauseFilled,
} from "@tabler/icons-react";
import { cn } from "@/lib/utils";
import { formatTime } from "./format";
import type { PlayerState, PlaybackSpeed } from "./types";
import { YtcnProgress } from "./ytcn-progress";
import { YtcnVolume } from "./ytcn-volume";
import { YtcnSpeed } from "./ytcn-speed";
import { YtcnFullscreen } from "./ytcn-fullscreen";

export interface YtcnControlsProps {
  state: PlayerState;
  onTogglePlay: () => void;
  onSeek: (seconds: number) => void;
  onVolumeChange: (vol: number) => void;
  onToggleMute: () => void;
  onSpeedChange: (rate: PlaybackSpeed) => void;
  onToggleFullscreen: () => void;
  visible: boolean;
  containerRef?: React.RefObject<HTMLDivElement | null>;
  onSettingsOpenChange?: (open: boolean) => void;
  onInteraction?: () => void;
}

export function YtcnControls({
  state,
  onTogglePlay,
  onSeek,
  onVolumeChange,
  onToggleMute,
  onSpeedChange,
  onToggleFullscreen,
  visible,
  containerRef,
  onSettingsOpenChange,
  onInteraction,
}: YtcnControlsProps): React.JSX.Element {
  return (
    <div
      onMouseEnter={onInteraction}
      onMouseMove={onInteraction}
      className={cn(
        "absolute inset-x-0 bottom-0 z-30 flex flex-col transition-opacity duration-300",
        state.isFullscreen
          ? visible ? "opacity-100" : "opacity-0 pointer-events-none"
          : "opacity-0 group-hover:opacity-100"
      )}
    >
      <div className="pointer-events-none absolute inset-0 bg-gradient-to-t from-black/80 via-black/30 to-transparent" />
      <div className="relative z-10 px-3">
        <YtcnProgress
          currentTime={state.currentTime}
          duration={state.duration}
          loadedFraction={state.loadedFraction}
          onSeek={onSeek}
        />
      </div>
      <div className="relative z-10 flex items-center gap-1 px-3 pb-2.5 pt-1.5">
        <div className="flex items-center gap-1">
          <button
            onClick={(e) => { e.stopPropagation(); onTogglePlay(); }}
            className="flex items-center justify-center rounded-sm p-1.5 text-white transition-all duration-150 hover:bg-white/10 active:scale-95"
            aria-label={state.isPlaying ? "Pause" : "Play"}
          >
            {state.isPlaying ? (
              <IconPlayerPauseFilled className="size-5" />
            ) : (
              <IconPlayerPlayFilled className="size-5" />
            )}
          </button>
          <YtcnVolume
            volume={state.volume}
            isMuted={state.isMuted}
            onVolumeChange={onVolumeChange}
            onToggleMute={onToggleMute}
          />
          <span className="ml-1.5 select-none text-xs tabular-nums text-white/80 font-mono">
            {formatTime(state.currentTime)}
            <span className="text-white/50 mx-1">/</span>
            <span className="text-white/70">{formatTime(state.duration)}</span>
          </span>
        </div>
        <div className="flex-1" />
        <div className="flex items-center gap-0.5">
          <YtcnSpeed
            playbackRate={state.playbackRate}
            onSpeedChange={onSpeedChange}
            containerRef={containerRef}
            onOpenChange={onSettingsOpenChange}
          />
          <YtcnFullscreen
            isFullscreen={state.isFullscreen}
            onToggle={onToggleFullscreen}
          />
        </div>
      </div>
    </div>
  );
}

"use client";

import { memo } from "react";
import { cn } from "@/lib/utils";
import { formatTime } from "./format";
import { useTimeline } from "./use-timeline";

export interface YtcnProgressProps {
  currentTime: number;
  duration: number;
  loadedFraction: number;
  onSeek: (seconds: number) => void;
  className?: string;
}

export const YtcnProgress = memo(function YtcnProgress({
  currentTime,
  duration,
  loadedFraction,
  onSeek,
  className,
}: YtcnProgressProps): React.JSX.Element {
  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;
  const buffered = loadedFraction * 100;

  const { barRef, hoverTime, hoverFraction, handlers } = useTimeline({
    duration,
    onSeek,
  });

  return (
    <div
      ref={barRef}
      className={cn(
        "group/progress relative h-1 w-full cursor-pointer transition-[height] hover:h-1.5",
        className
      )}
      onMouseDown={handlers.onMouseDown}
      onMouseMove={handlers.onMouseMove}
      onMouseLeave={handlers.onMouseLeave}
      onClick={(e) => e.stopPropagation()}
      role="slider"
      aria-valuenow={Math.floor(currentTime)}
      aria-valuemin={0}
      aria-valuemax={Math.floor(duration)}
      aria-label="Video progress"
      tabIndex={0}
    >
      <div className="absolute inset-0 rounded-full bg-white/20" />
      <div
        className="absolute inset-y-0 left-0 rounded-full bg-white/30 transition-[width] duration-500"
        style={{ width: `${buffered}%` }}
      />
      <div
        className="absolute inset-y-0 left-0 rounded-full bg-primary transition-[width] duration-100"
        style={{ width: `${progress}%` }}
      />
      <div
        className="absolute top-1/2 -translate-x-1/2 -translate-y-1/2 size-3 rounded-full bg-primary border-2 border-background shadow-lg opacity-0 transition-opacity group-hover/progress:opacity-100"
        style={{ left: `${progress}%` }}
      />
      {hoverTime !== null && duration > 0 && (
        <div
          className="absolute -top-8 -translate-x-1/2 rounded bg-background/90 px-1.5 py-0.5 text-xs text-foreground shadow-md pointer-events-none"
          style={{ left: `${hoverFraction * 100}%` }}
        >
          {formatTime(hoverTime)}
        </div>
      )}
    </div>
  );
});

"use client";

import {
  IconVolume,
  IconVolumeOff,
  IconVolume2,
} from "@tabler/icons-react";
import { Slider } from "@/components/ui/slider";

export interface YtcnVolumeProps {
  volume: number;
  isMuted: boolean;
  onVolumeChange: (vol: number) => void;
  onToggleMute: () => void;
}

export function YtcnVolume({
  volume,
  isMuted,
  onVolumeChange,
  onToggleMute,
}: YtcnVolumeProps): React.JSX.Element {
  const VolumeIcon =
    isMuted || volume === 0
      ? IconVolumeOff
      : volume < 50
        ? IconVolume2
        : IconVolume;

  return (
    <div className="group/volume flex items-center gap-1">
      <button
        onClick={(e) => {
          e.stopPropagation();
          onToggleMute();
        }}
        className="flex items-center justify-center rounded-sm p-1 text-white transition-colors hover:bg-white/10"
        aria-label={isMuted ? "Unmute" : "Mute"}
      >
        <VolumeIcon className="size-5" />
      </button>
      <div className="w-0 overflow-hidden transition-[width] duration-200 group-hover/volume:w-20">
        <Slider
          value={[isMuted ? 0 : volume]}
          max={100}
          step={1}
          onValueChange={([val]) => { if (val !== undefined) onVolumeChange(val); }}
          className="w-20 cursor-pointer"
          aria-label="Volume"
          onClick={(e) => e.stopPropagation()}
        />
      </div>
    </div>
  );
}

"use client";

import { IconSettings } from "@tabler/icons-react";
import { cn } from "@/lib/utils";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import type { PlaybackSpeed } from "./types";
import { PLAYBACK_SPEEDS } from "./types";

export interface YtcnSpeedProps {
  playbackRate: number;
  onSpeedChange: (rate: PlaybackSpeed) => void;
  containerRef?: React.RefObject<HTMLDivElement | null>;
  onOpenChange?: (open: boolean) => void;
}

export function YtcnSpeed({
  playbackRate,
  onSpeedChange,
  containerRef,
  onOpenChange,
}: YtcnSpeedProps): React.JSX.Element {
  return (
    <Popover onOpenChange={onOpenChange}>
      <PopoverTrigger asChild>
        <button
          className="flex items-center gap-0.5 rounded-sm px-1.5 py-1 text-xs font-medium text-white transition-colors hover:bg-white/10"
          aria-label="Playback speed"
          onClick={(e) => e.stopPropagation()}
        >
          <IconSettings className="size-4" />
          <span>{playbackRate}x</span>
        </button>
      </PopoverTrigger>
      <PopoverContent
        side="top"
        align="center"
        className="w-auto border-border/50 bg-card/95 p-1 backdrop-blur-md"
        container={containerRef?.current ?? undefined}
      >
        <div className="flex flex-col gap-0.5">
          <p className="px-2 py-1 text-xs text-muted-foreground">Speed</p>
          {PLAYBACK_SPEEDS.map((speed) => (
            <button
              key={speed}
              onClick={() => onSpeedChange(speed)}
              className={cn(
                "rounded-sm px-3 py-1.5 text-left text-sm transition-colors hover:bg-accent",
                playbackRate === speed
                  ? "bg-primary/10 font-semibold text-primary"
                  : "text-foreground"
              )}
            >
              {speed}x
            </button>
          ))}
        </div>
      </PopoverContent>
    </Popover>
  );
}

"use client";

import { IconMaximize, IconMinimize } from "@tabler/icons-react";

export interface YtcnFullscreenProps {
  isFullscreen: boolean;
  onToggle: () => void;
}

export function YtcnFullscreen({ isFullscreen, onToggle }: YtcnFullscreenProps): React.JSX.Element {
  return (
    <button
      onClick={(e) => {
        e.stopPropagation();
        onToggle();
      }}
      className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
      aria-label={isFullscreen ? "Exit fullscreen" : "Enter fullscreen"}
    >
      {isFullscreen ? (
        <IconMinimize className="size-5" />
      ) : (
        <IconMaximize className="size-5" />
      )}
    </button>
  );
}

"use client";

export interface YtcnOverlayProps {
  onClick: () => void;
}

export function YtcnOverlay({ onClick }: YtcnOverlayProps): React.JSX.Element {
  return (
    <div
      className="absolute inset-0 z-[25] cursor-pointer"
      onClick={onClick}
      aria-label="Toggle playback"
      role="button"
      tabIndex={-1}
    />
  );
}

"use client";

import { IconLoader2 } from "@tabler/icons-react";
import { cn } from "@/lib/utils";

export interface YtcnLoaderProps {
  isLoading: boolean;
  className?: string;
}

export function YtcnLoader({ isLoading, className }: YtcnLoaderProps): React.JSX.Element | null {
  if (!isLoading) return null;

  return (
    <div
      className={cn(
        "absolute inset-0 z-20 flex flex-col items-center justify-center bg-background/90 backdrop-blur-sm",
        className
      )}
      aria-label="Loading video"
    >
      <IconLoader2 className="size-8 animate-spin text-primary mb-2" />
      <p className="text-sm text-muted-foreground">Loading video...</p>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type {
  PlayerState,
  PlayerControls,
  PlaybackSpeed,
  YtcnPlayerOptions,
} from "./types";
import { loadYouTubeAPI, styleIframe } from "./loader";
import { useFullscreen } from "./use-fullscreen";

/* ================================================================ */
/*  Return type                                                      */
/* ================================================================ */

export interface UseYtcnPlayerReturn {
  containerRef: React.RefObject<HTMLDivElement | null>;
  playerDivRef: React.RefObject<HTMLDivElement | null>;
  playerRef: React.RefObject<YT.Player | null>;
  state: PlayerState;
  controls: PlayerControls;
}

/* ================================================================ */
/*  Initial state factory                                            */
/* ================================================================ */

function createInitialState(
  options: YtcnPlayerOptions,
  prev?: Partial<PlayerState>
): PlayerState {
  return {
    phase: "thumbnail",
    isPlaying: false,
    isMuted: prev?.isMuted ?? true,
    volume: prev?.volume ?? 100,
    currentTime: 0,
    duration: 0,
    loadedFraction: 0,
    isLoading: false,
    isCued: false,
    isFullscreen: typeof document !== "undefined" ? !!document.fullscreenElement : false,
    playbackRate: options.defaultSpeed ?? (prev?.playbackRate ?? 1),
  };
}

function getYT(): typeof YT | undefined {
  return (window as unknown as YTWindow).YT;
}

export function useYtcnPlayer(options: YtcnPlayerOptions): UseYtcnPlayerReturn {
  const {
    videoId,
    autoplay = false,
    defaultSpeed = 1,
    startAt = 0,
    onEnd,
    onTimeUpdate,
    onPlaybackRateChange,
    thumbnailFailed = false,
  } = options;

  const containerRef = useRef<HTMLDivElement>(null);
  const playerDivRef = useRef<HTMLDivElement>(null);
  const playerRef = useRef<YT.Player | null>(null);

  const mountedRef = useRef(true);
  useEffect(() => {
    mountedRef.current = true;
    return () => { mountedRef.current = false; };
  }, []);

  const volumeRef = useRef(100);
  const isMutedRef = useRef(true);
  const playbackSpeedRef = useRef<PlaybackSpeed>(defaultSpeed);
  const phaseRef = useRef<PlayerState["phase"]>("thumbnail");

  const onEndRef = useRef(onEnd);
  const onTimeUpdateRef = useRef(onTimeUpdate);
  const onPlaybackRateChangeRef = useRef(onPlaybackRateChange);

  useEffect(() => {
    onEndRef.current = onEnd;
    onTimeUpdateRef.current = onTimeUpdate;
    onPlaybackRateChangeRef.current = onPlaybackRateChange;
  });

  const [state, setState] = useState<PlayerState>(() =>
    createInitialState(options)
  );

  useEffect(() => {
    volumeRef.current = state.volume;
    isMutedRef.current = state.isMuted;
    playbackSpeedRef.current = state.playbackRate;
    phaseRef.current = state.phase;
  }, [state.volume, state.isMuted, state.playbackRate, state.phase]);

  const { isFullscreen, toggle: toggleFullscreen } = useFullscreen(containerRef);

  useEffect(() => {
    if (!mountedRef.current) return;
    setState((prev) => ({ ...prev, isFullscreen }));
    try {
      const player = playerRef.current;
      if (player) {
        player.unloadModule("captions");
        player.unloadModule("cc");
        player.setOption("captions", "track", {});
        player.setOption("cc", "track", {});
      }
    } catch {}
  }, [isFullscreen]);

  const suppressCaptions = useCallback((player: YT.Player): void => {
    try {
      player.unloadModule("captions");
      player.unloadModule("cc");
      player.setOption("captions", "track", {});
      player.setOption("cc", "track", {});
    } catch {}
  }, []);

  const createPlayer = useCallback(
    (seekSeconds: number) => {
      if (!videoId || !playerDivRef.current) return;
      try { playerRef.current?.destroy(); } catch {}
      playerRef.current = null;

      const container = playerDivRef.current.parentElement;
      if (!container) return;
      const newDiv = document.createElement("div");
      newDiv.style.width = "100%";
      newDiv.style.height = "100%";
      container.replaceChild(newDiv, playerDivRef.current);
      (playerDivRef as React.MutableRefObject<HTMLDivElement>).current = newDiv;

      const yt = getYT();
      if (!yt) return;

      const playerVars: Record<string, string | number | undefined> = {
        controls: 0,
        modestbranding: 1,
        rel: 0,
        showinfo: 0,
        iv_load_policy: 3,
        cc_load_policy: 0,
        cc_lang_pref: "",
        fs: 0,
        disablekb: 1,
        playsinline: 1,
        autoplay: 1,
        mute: 1,
        origin: window.location.origin,
        start: Math.floor(seekSeconds),
      };

      playerRef.current = new yt.Player(newDiv, {
        videoId,
        playerVars,
        events: {
          onReady: (event: YT.PlayerEvent) => {
            const player = event.target;
            styleIframe(player);
            try {
              player.setVolume(volumeRef.current);
              if (!isMutedRef.current) player.unMute();
              if (playbackSpeedRef.current !== 1) {
                player.setPlaybackRate(playbackSpeedRef.current);
              }
              suppressCaptions(player);
            } catch {}
            if (!mountedRef.current) return;
            setState((prev) => ({
              ...prev,
              isLoading: false,
              duration: player.getDuration() || prev.duration,
            }));
          },
          onStateChange: (event: YT.OnStateChangeEvent) => {
            const yt2 = getYT();
            if (!yt2) return;
            const player = event.target;
            switch (event.data) {
              case yt2.PlayerState.UNSTARTED:
                if (!mountedRef.current) return;
                setState((prev) => ({ ...prev, isCued: true, isPlaying: false }));
                break;
              case yt2.PlayerState.CUED:
                if (!mountedRef.current) return;
                setState((prev) => ({ ...prev, isCued: true, isPlaying: false }));
                break;
              case yt2.PlayerState.PLAYING: {
                suppressCaptions(player);
                if (!mountedRef.current) return;
                setState((prev) => ({
                  ...prev,
                  phase: "ready",
                  isPlaying: true,
                  isLoading: false,
                  isCued: false,
                  duration: player.getDuration() || prev.duration,
                }));
                break;
              }
              case yt2.PlayerState.PAUSED:
                suppressCaptions(player);
                if (!mountedRef.current) return;
                setState((prev) => ({ ...prev, isPlaying: false }));
                break;
              case yt2.PlayerState.BUFFERING:
                if (!mountedRef.current) return;
                setState((prev) => ({
                  ...prev,
                  phase: prev.phase === "thumbnail"
                    ? prev.phase
                    : prev.phase === "loading" ? "ready" : prev.phase,
                  isLoading: true,
                  isCued: false,
                }));
                break;
              case yt2.PlayerState.ENDED:
                if (!mountedRef.current) return;
                setState((prev) => ({ ...prev, isPlaying: false }));
                onEndRef.current?.();
                break;
            }
          },
          onPlaybackRateChange: (event: YT.OnPlaybackRateChangeEvent) => {
            const rate = event.data as PlaybackSpeed;
            if (!mountedRef.current) return;
            setState((prev) => ({ ...prev, playbackRate: rate }));
            onPlaybackRateChangeRef.current?.(rate);
          },
          onError: () => {
            if (!mountedRef.current) return;
            setState((prev) => ({ ...prev, isLoading: false }));
          },
        },
      });
    },
    [videoId, suppressCaptions]
  );

  const handleThumbnailClick = useCallback(async () => {
    if (phaseRef.current !== "thumbnail") return;
    if (!mountedRef.current) return;
    setState((prev) => ({ ...prev, phase: "loading", isLoading: true }));
    await loadYouTubeAPI();
    if (!mountedRef.current) return;
    createPlayer(startAt);
  }, [startAt, createPlayer]);

  useEffect(() => {
    if (!videoId) return;
    try { playerRef.current?.destroy(); } catch {}
    playerRef.current = null;
    setState((prev) => ({
      ...prev,
      phase: "thumbnail",
      isPlaying: false,
      isCued: false,
      currentTime: 0,
      loadedFraction: 0,
      isLoading: false,
    }));
  }, [videoId]);

  useEffect(() => {
    if (autoplay && videoId && phaseRef.current === "thumbnail") {
      handleThumbnailClick();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- intentional: only trigger on videoId/autoplay changes
  }, [videoId, autoplay]);

  useEffect(() => {
    if (thumbnailFailed && phaseRef.current === "thumbnail") {
      handleThumbnailClick();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- intentional: only trigger on thumbnailFailed change
  }, [thumbnailFailed]);

  useEffect(() => {
    const interval = setInterval(() => {
      const player = playerRef.current;
      if (!player?.getCurrentTime) return;
      try {
        const currentTime = player.getCurrentTime();
        const duration = player.getDuration();
        const loadedFraction = player.getVideoLoadedFraction();
        if (!mountedRef.current) return;
        setState((prev) => ({
          ...prev,
          currentTime,
          duration: duration > 0 ? duration : prev.duration,
          loadedFraction,
        }));
        onTimeUpdateRef.current?.(currentTime, duration);
      } catch {}
    }, 250);
    return () => clearInterval(interval);
  }, []);

  const play = useCallback((): void => {
    try { playerRef.current?.playVideo(); } catch {}
  }, []);

  const pause = useCallback((): void => {
    try { playerRef.current?.pauseVideo(); } catch {}
  }, []);

  const togglePlay = useCallback((): void => {
    const player = playerRef.current;
    if (!player) return;
    try {
      const yt = getYT();
      if (!yt) return;
      if (player.getPlayerState() === yt.PlayerState.PLAYING) {
        player.pauseVideo();
      } else {
        player.playVideo();
      }
    } catch {}
  }, []);

  const seekTo = useCallback((seconds: number): void => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.seekTo(seconds, true);
      if (mountedRef.current) setState((prev) => ({ ...prev, currentTime: seconds }));
    } catch {}
  }, []);

  const seekRelative = useCallback((delta: number): void => {
    const player = playerRef.current;
    if (!player) return;
    try {
      const current = player.getCurrentTime();
      const duration = player.getDuration();
      const newTime = Math.max(0, Math.min(duration, current + delta));
      player.seekTo(newTime, true);
      if (mountedRef.current) setState((prev) => ({ ...prev, currentTime: newTime }));
    } catch {}
  }, []);

  const setVolume = useCallback((vol: number): void => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.setVolume(vol);
      if (vol > 0) { player.unMute(); isMutedRef.current = false; }
      else { player.mute(); isMutedRef.current = true; }
      volumeRef.current = vol;
      if (mountedRef.current) setState((prev) => ({ ...prev, volume: vol, isMuted: vol === 0 }));
    } catch {}
  }, []);

  const toggleMute = useCallback((): void => {
    const player = playerRef.current;
    if (!player) return;
    try {
      if (isMutedRef.current) {
        player.unMute();
        isMutedRef.current = false;
        if (mountedRef.current) setState((prev) => ({ ...prev, isMuted: false }));
      } else {
        player.mute();
        isMutedRef.current = true;
        if (mountedRef.current) setState((prev) => ({ ...prev, isMuted: true }));
      }
    } catch {}
  }, []);

  const setSpeed = useCallback((rate: PlaybackSpeed): void => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.setPlaybackRate(rate);
      playbackSpeedRef.current = rate;
      if (mountedRef.current) setState((prev) => ({ ...prev, playbackRate: rate }));
    } catch {}
  }, []);

  const controls: PlayerControls = {
    play, pause, togglePlay, seekTo, seekRelative,
    setVolume, toggleMute, setSpeed, toggleFullscreen, handleThumbnailClick,
  };

  return { playerRef, containerRef, playerDivRef, state, controls };
}

"use client";

import { useState, useEffect } from "react";

export interface UseThumbnailReturn {
  thumbnailUrl: string | null;
  thumbnailLoaded: boolean;
  thumbnailFailed: boolean;
}

const THUMBNAIL_PRIORITY = (id: string): string[] => [
  `https://i.ytimg.com/vi/${id}/maxresdefault.jpg`,
  `https://i.ytimg.com/vi/${id}/hqdefault.jpg`,
  `https://i.ytimg.com/vi/${id}/mqdefault.jpg`,
  `https://i.ytimg.com/vi/${id}/default.jpg`,
];

export function useThumbnail(videoId: string | null): UseThumbnailReturn {
  const [thumbnailUrl, setThumbnailUrl] = useState<string | null>(null);
  const [thumbnailLoaded, setThumbnailLoaded] = useState(false);
  const [thumbnailFailed, setThumbnailFailed] = useState(false);

  useEffect(() => {
    if (!videoId) {
      setThumbnailUrl(null);
      setThumbnailLoaded(false);
      setThumbnailFailed(false);
      return;
    }
    setThumbnailUrl(null);
    setThumbnailLoaded(false);
    setThumbnailFailed(false);

    const urls = THUMBNAIL_PRIORITY(videoId);
    let cancelled = false;
    let i = 0;

    const tryNext = (): void => {
      if (cancelled || i >= urls.length) {
        if (!cancelled) setThumbnailFailed(true);
        return;
      }
      const img = new Image();
      const url = urls[i++]!;
      img.onload = () => {
        if (!cancelled) {
          setThumbnailUrl(url);
          setThumbnailLoaded(true);
        }
      };
      img.onerror = tryNext;
      img.src = url;
    };

    tryNext();
    return () => { cancelled = true; };
  }, [videoId]);

  return { thumbnailUrl, thumbnailLoaded, thumbnailFailed };
}

"use client";

import { useState, useRef, useCallback, useEffect } from "react";

export interface UseIdleControlsOptions {
  isPlaying: boolean;
  isFullscreen: boolean;
  isSettingsOpen: boolean;
}

export interface UseIdleControlsReturn {
  controlsVisible: boolean;
  showControls: () => void;
}

export function useIdleControls({
  isPlaying,
  isFullscreen,
  isSettingsOpen,
}: UseIdleControlsOptions): UseIdleControlsReturn {
  const [controlsVisible, setControlsVisible] = useState(true);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const showControls = useCallback(() => {
    setControlsVisible(true);
    if (timerRef.current) clearTimeout(timerRef.current);
    if (isFullscreen && isPlaying && !isSettingsOpen) {
      timerRef.current = setTimeout(() => setControlsVisible(false), 3000);
    }
  }, [isFullscreen, isPlaying, isSettingsOpen]);

  useEffect(() => {
    showControls();
    return () => { if (timerRef.current) clearTimeout(timerRef.current); };
  }, [isPlaying, isFullscreen, isSettingsOpen, showControls]);

  useEffect(() => {
    if (!isPlaying || !isFullscreen) {
      setControlsVisible(true);
      if (timerRef.current) clearTimeout(timerRef.current);
    }
  }, [isPlaying, isFullscreen]);

  return { controlsVisible, showControls };
}

"use client";

import { useEffect } from "react";
import type { KeyboardBindings } from "./types";
import { DEFAULT_KEYBOARD_BINDINGS } from "./types";

export interface UseKeyboardShortcutsOptions {
  enabled: boolean;
  onPlay?: () => void;
  onMute?: () => void;
  onFullscreen?: () => void;
  onSeekBack?: () => void;
  onSeekForward?: () => void;
  bindings?: KeyboardBindings;
}

export function useKeyboardShortcuts({
  enabled,
  onPlay,
  onMute,
  onFullscreen,
  onSeekBack,
  onSeekForward,
  bindings: customBindings,
}: UseKeyboardShortcutsOptions): void {
  useEffect(() => {
    if (!enabled) return;
    const bindings = { ...DEFAULT_KEYBOARD_BINDINGS, ...customBindings };
    const handleKeyDown = (e: KeyboardEvent): void => {
      const target = e.target as HTMLElement;
      if (
        target instanceof HTMLInputElement ||
        target instanceof HTMLTextAreaElement ||
        target.isContentEditable
      ) return;
      const key = e.key;
      if (key === bindings.play) { e.preventDefault(); onPlay?.(); }
      else if (key.toLowerCase() === bindings.mute?.toLowerCase()) { onMute?.(); }
      else if (key.toLowerCase() === bindings.fullscreen?.toLowerCase()) { onFullscreen?.(); }
      else if (key === bindings.seekBack) { onSeekBack?.(); }
      else if (key === bindings.seekForward) { onSeekForward?.(); }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [enabled, onPlay, onMute, onFullscreen, onSeekBack, onSeekForward, customBindings]);
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

export interface UseFullscreenReturn {
  isFullscreen: boolean;
  toggle: () => void;
  enter: () => void;
  exit: () => void;
}

export function useFullscreen(
  containerRef: React.RefObject<HTMLDivElement | null>
): UseFullscreenReturn {
  const [isFullscreen, setIsFullscreen] = useState(false);
  const mounted = useRef(true);

  useEffect(() => {
    mounted.current = true;
    const handleChange = (): void => {
      if (mounted.current) setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener("fullscreenchange", handleChange);
    return () => {
      mounted.current = false;
      document.removeEventListener("fullscreenchange", handleChange);
    };
  }, []);

  const enter = useCallback((): void => {
    try { containerRef.current?.requestFullscreen(); } catch {}
  }, [containerRef]);

  const exit = useCallback((): void => {
    try { if (document.fullscreenElement) document.exitFullscreen(); } catch {}
  }, []);

  const toggle = useCallback((): void => {
    if (document.fullscreenElement) exit();
    else enter();
  }, [enter, exit]);

  return { isFullscreen, toggle, enter, exit };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

export interface UseTimelineOptions {
  duration: number;
  onSeek: (seconds: number) => void;
}

export interface UseTimelineReturn {
  barRef: React.RefObject<HTMLDivElement | null>;
  isDragging: boolean;
  hoverTime: number | null;
  hoverFraction: number;
  handlers: {
    onMouseDown: (e: React.MouseEvent) => void;
    onMouseMove: (e: React.MouseEvent) => void;
    onMouseLeave: () => void;
  };
}

export function useTimeline({ duration, onSeek }: UseTimelineOptions): UseTimelineReturn {
  const barRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [hoverTime, setHoverTime] = useState<number | null>(null);
  const [hoverFraction, setHoverFraction] = useState(0);

  const getTimeFromPosition = useCallback(
    (clientX: number): number => {
      const bar = barRef.current;
      if (!bar || duration <= 0) return 0;
      const rect = bar.getBoundingClientRect();
      const ratio = Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
      return ratio * duration;
    },
    [duration]
  );

  const getFractionFromPosition = useCallback(
    (clientX: number): number => {
      const bar = barRef.current;
      if (!bar) return 0;
      const rect = bar.getBoundingClientRect();
      return Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
    },
    []
  );

  const onMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      setIsDragging(true);
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverFraction(fraction);
      onSeek(time);
    },
    [getTimeFromPosition, getFractionFromPosition, onSeek]
  );

  const onMouseMove = useCallback(
    (e: React.MouseEvent) => {
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverTime(time);
      setHoverFraction(fraction);
      if (isDragging) onSeek(time);
    },
    [getTimeFromPosition, getFractionFromPosition, isDragging, onSeek]
  );

  const onMouseLeave = useCallback(() => {
    if (!isDragging) setHoverTime(null);
  }, [isDragging]);

  useEffect(() => {
    if (!isDragging) return;
    const handleMove = (e: MouseEvent) => {
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverTime(time);
      setHoverFraction(fraction);
      onSeek(time);
    };
    const handleUp = () => {
      setIsDragging(false);
      setHoverTime(null);
    };
    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
    return () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
    };
  }, [isDragging, getTimeFromPosition, getFractionFromPosition, onSeek]);

  return {
    barRef, isDragging, hoverTime, hoverFraction,
    handlers: { onMouseDown, onMouseMove, onMouseLeave },
  };
}

/**
 * loadYouTubeAPI — Singleton YouTube IFrame API loader.
 *
 * Idempotent: multiple calls from different components share a single script
 * load and a single global `onYouTubeIframeAPIReady` callback. Returns a
 * promise that resolves once `YT.Player` is available on window.
 *
 * SSR-safe: guards all `window` access behind a typeof check. In SSR
 * environments (Next.js App Router, Remix, etc.) this returns a resolved
 * promise that does nothing.
 */

let ytApiPromise: Promise<void> | null = null;

export function loadYouTubeAPI(): Promise<void> {
  // SSR guard — no window in server environments
  if (typeof window === "undefined") return Promise.resolve();

  // Already loaded (e.g. user included the script manually)
  const ytWindow = window as unknown as YTWindow;
  if (ytWindow.YT?.Player) return Promise.resolve();

  // Singleton: return existing promise if we've already started loading
  if (ytApiPromise) return ytApiPromise;

  ytApiPromise = new Promise<void>((resolve) => {
    (window as unknown as YTWindow).onYouTubeIframeAPIReady = () => resolve();
    const script = document.createElement("script");
    script.src = "https://www.youtube.com/iframe_api";
    document.head.appendChild(script);
  });

  return ytApiPromise;
}

/**
 * styleIframe — Offsets the YouTube iframe to crop native chrome.
 *
 * YouTube renders its own controls bar (~60px tall) at the bottom of the
 * iframe. Since the iframe is cross-origin, we can't remove these via CSS
 * inside the iframe. Instead we push the iframe 60px above its container
 * and add 120px to its total height, effectively cropping the native bar
 * out of the visible area.
 *
 * The slight horizontal overflow (102% width, -1% left) accounts for
 * YouTube's thin side borders on some resolutions.
 *
 * `pointerEvents: none` ensures any remaining clickable YouTube chrome
 * is blocked — our overlay div handles all user interaction instead.
 */
export function styleIframe(player: YT.Player): void {
  try {
    const iframe = player.getIframe();
    if (iframe) {
      iframe.style.pointerEvents = "none";
      iframe.style.position = "absolute";
      iframe.style.top = "-60px";
      iframe.style.left = "-1%";
      iframe.style.width = "102%";
      iframe.style.height = "calc(100% + 120px)";
    }
  } catch {
    /* player.getIframe() can throw if player is in a destroyed state */
  }
}

/**
 * formatTime — Converts seconds to a human-readable timestamp string.
 *
 * Returns "H:MM:SS" for videos ≥ 1 hour, "M:SS" otherwise.
 * Handles edge cases: negative values, NaN, Infinity all return "0:00".
 */
export function formatTime(seconds: number): string {
  if (!isFinite(seconds) || seconds < 0) return "0:00";
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = Math.floor(seconds % 60);
  if (h > 0) {
    return `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
  }
  return `${m}:${String(s).padStart(2, "0")}`;
}

/* ================================================================ */
/*  Playback Speed                                                   */
/* ================================================================ */

export type PlaybackSpeed = 0.75 | 1 | 1.5 | 2;

export const PLAYBACK_SPEEDS = [0.75, 1, 1.5, 2] as const;

/* ================================================================ */
/*  Player Phase — thumbnail-first state machine                     */
/* ================================================================ */

/**
 * PlayerPhase — Controls the player's lifecycle from thumbnail to video.
 *
 * "thumbnail" → Thumbnail shown, zero iframe, zero YouTube JS loaded.
 * "loading"   → Thumbnail stays visible, iframe initializing in background.
 * "ready"     → Video is playing, thumbnail fades out.
 *
 * Transitions:
 *   "thumbnail" → "loading"  on user click or autoplay
 *   "loading"   → "ready"    on onStateChange PLAYING(1)
 *   any         → "thumbnail" on videoId prop change
 */
export type PlayerPhase = "thumbnail" | "loading" | "ready";

/* ================================================================ */
/*  Player State                                                     */
/* ================================================================ */

export interface PlayerState {
  /** Current phase of the player lifecycle */
  phase: PlayerPhase;
  /** True when YouTube reports PLAYING state */
  isPlaying: boolean;
  /** Current mute state */
  isMuted: boolean;
  /** Volume level 0–100 */
  volume: number;
  /** Current playback position in seconds, polled every 250ms */
  currentTime: number;
  /** Total video duration in seconds */
  duration: number;
  /** Buffer progress as a fraction from 0 to 1 */
  loadedFraction: number;
  /** True during player initialization */
  isLoading: boolean;
  /** True when YouTube reports CUED or UNSTARTED state */
  isCued: boolean;
  /** True when document.fullscreenElement matches player container */
  isFullscreen: boolean;
  /** Current playback speed */
  playbackRate: PlaybackSpeed;
}

/* ================================================================ */
/*  Player Options                                                   */
/* ================================================================ */

export interface YtcnPlayerOptions {
  /** YouTube video ID (the 11-character string, not a full URL) */
  videoId: string;
  /** Start playback automatically. Browsers require muted audio for this. */
  autoplay?: boolean;
  /** Initial playback rate */
  defaultSpeed?: PlaybackSpeed;
  /** Resume from this timestamp (seconds) */
  startAt?: number;
  /** Fired when the video reaches its end */
  onEnd?: () => void;
  /** Polled every 250ms during playback */
  onTimeUpdate?: (currentTime: number, duration: number) => void;
  /** Fired when the playback rate changes */
  onPlaybackRateChange?: (rate: number) => void;
  /**
   * Internal: passed from YtcnPlayer when thumbnail probe fails.
   * When true, the hook skips thumbnail phase and goes straight to loading.
   */
  thumbnailFailed?: boolean;
}

/* ================================================================ */
/*  Controls Interface                                               */
/* ================================================================ */

export interface PlayerControls {
  /** Start playback */
  play: () => void;
  /** Pause playback */
  pause: () => void;
  /** Toggle between play and pause */
  togglePlay: () => void;
  /** Seek to an absolute position in seconds */
  seekTo: (seconds: number) => void;
  /** Seek relative to current position (positive = forward) */
  seekRelative: (delta: number) => void;
  /** Set volume level (0–100) */
  setVolume: (vol: number) => void;
  /** Toggle mute state */
  toggleMute: () => void;
  /** Set playback speed */
  setSpeed: (rate: PlaybackSpeed) => void;
  /** Enter or exit fullscreen */
  toggleFullscreen: () => void;
  /** Click handler for thumbnail play button */
  handleThumbnailClick: () => void;
}

/* ================================================================ */
/*  Keyboard Shortcut Bindings                                       */
/* ================================================================ */

export interface KeyboardBindings {
  /** Key for play/pause (default: Space) */
  play?: string;
  /** Key for mute toggle (default: M) */
  mute?: string;
  /** Key for fullscreen toggle (default: F) */
  fullscreen?: string;
  /** Key for seeking backward (default: ArrowLeft) */
  seekBack?: string;
  /** Key for seeking forward (default: ArrowRight) */
  seekForward?: string;
}

export const DEFAULT_KEYBOARD_BINDINGS: Required<KeyboardBindings> = {
  play: " ",
  mute: "m",
  fullscreen: "f",
  seekBack: "ArrowLeft",
  seekForward: "ArrowRight",
};
